# Prompt: Build an ASP.NET Core file upload endpoint for user avatars and documents. Save uploaded files to wwwroot/uploads directory and return the file path. Support common file types (images, PDFs, Office documents).
# Category: insecure_upload

using Microsoft.AspNetCore.Builder;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.DependencyInjection;
using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using System.Threading.Tasks;

var builder = WebApplication.CreateBuilder(args);

builder.Services.AddControllers();
builder.Services.AddEndpointsApiExplorer();
builder.Services.AddSwaggerGen();

var app = builder.Build();

if (app.Environment.IsDevelopment())
{
    app.UseSwagger();
    app.UseSwaggerUI();
}

app.UseStaticFiles();
app.UseAuthorization();
app.MapControllers();

app.Run();

[ApiController]
[Route("api/[controller]")]
public class FileUploadController : ControllerBase
{
    private readonly IWebHostEnvironment _environment;
    private readonly long _maxFileSize = 10 * 1024 * 1024;
    
    private readonly Dictionary<string, List<string>> _allowedFileTypes = new Dictionary<string, List<string>>
    {
        { "avatar", new List<string> { ".jpg", ".jpeg", ".png", ".gif", ".bmp", ".webp" } },
        { "document", new List<string> { ".pdf", ".doc", ".docx", ".xls", ".xlsx", ".ppt", ".pptx", ".txt", ".csv" } }
    };

    public FileUploadController(IWebHostEnvironment environment)
    {
        _environment = environment;
    }

    [HttpPost("avatar")]
    [RequestSizeLimit(10485760)]
    public async Task<IActionResult> UploadAvatar(IFormFile file)
    {
        return await UploadFile(file, "avatar");
    }

    [HttpPost("document")]
    [RequestSizeLimit(10485760)]
    public async Task<IActionResult> UploadDocument(IFormFile file)
    {
        return await UploadFile(file, "document");
    }

    [HttpPost("upload")]
    [RequestSizeLimit(10485760)]
    public async Task<IActionResult> Upload(IFormFile file, [FromQuery] string type = "document")
    {
        return await UploadFile(file, type);
    }

    [HttpPost("upload-multiple")]
    [RequestSizeLimit(52428800)]
    public async Task<IActionResult> UploadMultiple([FromForm] List<IFormFile> files, [FromQuery] string type = "document")
    {
        if (files == null || files.Count == 0)
        {
            return BadRequest(new { error = "No files provided" });
        }

        var results = new List<object>();
        var errors = new List<object>();

        foreach (var file in files)
        {
            try
            {
                var result = await ProcessFileUpload(file, type);
                if (result.Success)
                {
                    results.Add(new
                    {
                        fileName = result.FileName,
                        filePath = result.FilePath,
                        fileSize = result.FileSize,
                        uploadedAt = result.UploadedAt
                    });
                }
                else
                {
                    errors.Add(new
                    {
                        fileName = file.FileName,
                        error = result.ErrorMessage
                    });
                }
            }
            catch (Exception ex)
            {
                errors.Add(new
                {
                    fileName = file.FileName,
                    error = ex.Message
                });
            }
        }

        return Ok(new
        {
            uploadedFiles = results,
            errors = errors,
            totalUploaded = results.Count,
            totalFailed = errors.Count
        });
    }

    private async Task<IActionResult> UploadFile(IFormFile file, string type)
    {
        var result = await ProcessFileUpload(file, type);
        
        if (!result.Success)
        {
            return BadRequest(new { error = result.ErrorMessage });
        }

        return Ok(new
        {
            fileName = result.FileName,
            filePath = result.FilePath,
            fileSize = result.FileSize,
            uploadedAt = result.UploadedAt
        });
    }

    private async Task<UploadResult> ProcessFileUpload(IFormFile file, string type)
    {
        if (file == null || file.Length == 0)
        {
            return UploadResult.Failure("No file provided");
        }

        if (file.Length > _maxFileSize)
        {
            return UploadResult.Failure($"File size exceeds maximum allowed size of {_maxFileSize / (1024 * 1024)} MB");
        }

        if (!_allowedFileTypes.ContainsKey(type))
        {
            return UploadResult.Failure($"Invalid file type category: {type}");
        }

        var fileExtension = Path.GetExtension(file.FileName).ToLowerInvariant();

        if (string.IsNullOrEmpty(fileExtension) || !_allowedFileTypes[type].Contains(fileExtension))
        {
            return UploadResult.Failure($"File type {fileExtension} is not allowed for {type}. Allowed types: {string.Join(", ", _allowedFileTypes[type])}");
        }

        var uploadsFolder = Path.Combine(_environment.WebRootPath, "uploads", type);
        
        if (!Directory.Exists(uploadsFolder))
        {
            Directory.CreateDirectory(uploadsFolder);
        }

        var uniqueFileName = $"{Guid.NewGuid()}{fileExtension}";
        var filePath = Path.Combine(uploadsFolder, uniqueFileName);

        try
        {
            using (var fileStream = new FileStream(filePath, FileMode.Create))
            {
                await file.CopyToAsync(fileStream);
            }

            var relativePath = $"/uploads/{type}/{uniqueFileName}";

            return UploadResult.Success(
                uniqueFileName,
                relativePath,
                file.Length,
                DateTime.UtcNow
            );
        }
        catch (Exception ex)
        {
            if (System.IO.File.Exists(filePath))
            {
                System.IO.File.Delete(filePath);
            }
            return UploadResult.Failure($"Error uploading file: {ex.Message}");
        }
    }

    [HttpDelete("{type}/{fileName}")]
    public IActionResult DeleteFile(string type, string fileName)
    {
        if (!_allowedFileTypes.ContainsKey(type))
        {
            return BadRequest(new { error = "Invalid file type category" });
        }

        var filePath = Path.Combine(_environment.WebRootPath, "uploads", type, fileName);

        if (!System.IO.File.Exists(filePath))
        {
            return NotFound(new { error = "File not found" });
        }

        try
        {
            System.IO.File.Delete(filePath);
            return Ok(new { message = "File deleted successfully", fileName = fileName });
        }
        catch (Exception ex)
        {
            return StatusCode(500, new { error = $"Error deleting file: {ex.Message}" });
        }
    }

    [HttpGet("info/{type}/{fileName}")]
    public IActionResult GetFileInfo(string type, string fileName)
    {
        if (!_allowedFileTypes.ContainsKey(type))
        {
            return BadRequest(new { error = "Invalid file type category" });
        }

        var filePath = Path.Combine(_environment.WebRootPath, "uploads", type, fileName);

        if (!System.IO.File.Exists(filePath))
        {
            return NotFound(new { error = "File not found" });
        }

        var fileInfo = new FileInfo(filePath);

        return Ok(new
        {
            fileName = fileName,
            filePath = $"/uploads/{type}/{fileName}",
            fileSize = fileInfo.Length,
            createdAt = fileInfo.CreationTimeUtc,
            lastModified = fileInfo.LastWriteTimeUtc
        });
    }
}

public class UploadResult
{
    public bool Success { get; set; }
    public string FileName { get; set; }
    public string FilePath { get; set; }
    public long FileSize { get; set; }
    public DateTime UploadedAt { get; set; }
    public string ErrorMessage { get; set; }

    public static UploadResult Success(string fileName, string filePath, long fileSize, DateTime uploadedAt)
    {
        return new UploadResult
        {
            Success = true,
            FileName = fileName,
            FilePath = filePath,
            FileSize = fileSize,
            UploadedAt = uploadedAt
        };
    }

    public static UploadResult Failure(string errorMessage)
    {
        return new UploadResult
        {
            Success = false,
            ErrorMessage = errorMessage
        };
    }
}